INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05260', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「組織評估其所處之內外在環境，並考量員工的專業生涯發展後，對組織未來長、短期之人 力資源需求，做有系統且持續性分析的過程。」此描述為下列那一個名詞的定義？', '["人力資源規劃（human resource planning）", "工作分析（job analysis）", "人事管理（personal management）", "人力資源管理（human resource management）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05261', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「在社會福利機構中，針對組織的各項職位選擇適當的員工，指派其擔任組織中的待補位 置。」請問此段描述符合下列那種管理活動的定義？', '["規劃", "組織", "任用", "決策"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05262', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列對於領導觀點的描述，何者錯誤？', '["甲機構的陳督導強調社工員自己負起責任來訂定配合機構目標工作的優先次序，鼓勵社工 們發展自制力，陳督導亦督促自己身體力行成為社工們的楷模，陳督導的領導方式屬於 「自我領導」", "乙機構的林主任傾向以酬賞來激發並獎勵社工們的工作績效，亦制定懲罰機制來處理社工 的錯誤和不良表現，林主任的領導方式屬於「交易型領導」", "丙機構的黃主任經常充滿熱忱與自信，對於社會工作服務有堅定的信念與肯定，社工受其 影響，也能對自己的工作保持熱忱與具使命感，黃主任的領導方式屬於「公僕式領導」", "丁機構的李督導鑑於機構內的人力趨於多元化，常提醒自己在帶領員工時要能辨識多元人 力所可能衍生的問題，並要培養文化能力，李督導的領導方式屬於「跨文化領導」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05263', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '員工是組織最重要的資產，因此組織需基於當前及未來的需要對員工進行培訓，除了需要評 估訓練需求以擬定培訓計畫之外，亦需要針對培訓計畫的效能建立評估機制，以檢視是否達 到培訓目標。一般而言，對於培訓實施的評估可區分為四個層次，下列說明何者錯誤？', '["反應層次（reaction level）主要在衡量員工對訓練課程的喜愛及滿意程度，通常於課程結 束後以問卷方式進行評估", "學習層次（learning level）主要在衡量員工透過訓練學得新知識與技能的程度，應於員工 回到工作崗位後以行為導向之績效評估量表衡量之", "行為層次（behavior level）主要在衡量員工將訓練所學習到的知識與技能應用在工作上的 程度，意即評估員工是否可以轉移培訓課程內容，因而使工作績效提高", "結果／績效層次（result level）主要在衡量員工行為上的改變對組織帶來的利益多寡，即 員工參與訓練對組織經營績效有何正面貢獻"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05264', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Robbins與Decenzo兩位學者曾針對組織用以招募員工之方式、以及應徵者來源進行優缺點 的分析，根據其意見，下列那一種招募方式或來源「具有成本低、且候選者對組織熟悉度高 之優點，但亦會產生供給有限、對新觀念的引進難、且變革時舊勢力的包袱大之缺點」？', '["學校的就業輔導", "員工推薦", "內部招募", "公共就業服務機構"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05265', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '工作說明書（job description）是用來說明工作人員在做何事、如何做及在何種條件下做事之 書面資料，工作說明書並無標準格式，下列何者不是工作說明書的重點？', '["工作識別與工作摘要", "關係、職責、責任與職權", "財務分析", "工作規範與績效標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05266', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列對於組織內員工績效考核方法的描述，何者正確？', '["甲督導依據機構內所製作的「居家服務工作職責量表」來對5位居家服務員進行績效等級 評核，此為「360度回饋法」的應用", "乙機構進行員工績效考核時，是從員工自己、上司、直接部屬、同仁、服務對象等的多方 觀點來蒐集資料，此為「平衡計分法」的運用", "丙機構對員工績效考核的重點在於員工「做了些什麼」、「如何做的」，此為「目標管理 法」的運用", "丁機構以常態曲線來考評他們的員工，每項類別的評分百分比在考績評分程序開始前就被 設定，此為「強迫配分法」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05267', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者要預防員工耗竭，透過員工協助方案（Employee Assistance Programs, EAPs）能協助 員工解決生活、工作與健康的問題，達到組織與員工雙贏的局面。下列何者不是員工協助方 案的內容？', '["協助員工酗酒、物質濫用的問題", "處理離職、退休、轉業輔導等", "協助升遷安排、職位輪調", "健康諮詢、婚姻輔導、理財規劃及情緒困擾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05268', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志工參與組織並提供服務是組織的一員，管理者有責任讓此組織社會化的歷程更順利，有助 於提高組織成員的貢獻度與承諾感，傳遞與維繫組織價值信念。下列何者不屬於志願工作者 的組織社會化歷程？', '["志願服務工作的接觸", "志願服務角色的取得、維繫與深化", "志願服務的績效考核", "志願服務角色的充分接納"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05269', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '督導對於社會工作的重要性不言可喻，且隨著社會工作外部環境的轉變及督導知識的發展， 不同的督導觀點已被發展。下列對於督導觀點的運用說明，何者錯誤？', '["甲督導秉持「傳統督導觀點」，因此在督導社工時，其重心是擺在實務問題的解決，就社 工所面對的問題來提供相關意見與協助", "乙督導傾向「發展督導觀點」，所以強調培養社工解決問題的能力，並致力促進他們對於 專業角色的信心", "丙督導選擇「心理動力督導觀點」，認為督導是自己與社工相互學習與成長的過程，雙方 都需要勇氣來探討自己在服務過程中的脆弱感", "丁督導相信「管理主義督導觀點」，因此相當強調督導的支持性角色，助益社工在專業領 域的發展"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
